System.register([],function(e,n){var t,a,o,s,c,i;return{setters:[],execute:function(){a=(e,n,t,a,o,s)=>({id:e,type:"dialogue",speaker:n,speakerKey:t,text:a,sprite:o?{key:o,position:"linmo"===o?"left":"right"}:void 0,effects:s}),o=(e,n,t)=>({id:e,type:"choice",text:n,choices:t,speaker:""}),s=(e,n,t,a,o)=>({id:e,type:"quiz",text:n,quiz:t,onCorrect:a,onWrong:o,speaker:""}),c=(e,n,t,a)=>({id:e,type:"cg",text:n,background:t,speaker:"",cgImage:a}),i=(e,n)=>({id:e,type:"system",text:n,speaker:""}),e("prologueScript",[(t=(e,n,t)=>({id:e,type:"narration",text:n,speaker:"",background:t,sprite:void 0}))("s0-1-1","他们说，时间是一条单行道。\n他们说，过去无法改变。\n他们错了。","dark"),c("s0-1-2","一枚绿色的量子生物酶分子在X射线晶体衍射图谱中缓缓旋转，光谱在它周围扭曲成螺旋。\n\n我叫林墨。\n这是我入职普罗米修斯生物科技的第一天。\n也是我第一次死亡的日子。","black","/images/cg/cg_reincarnation_awakening.png"),t("s0-1-3","当然，现在的我还什么都不知道。\n我只知道，这份工作的薪水是上一份的三倍。\n对于一个刚被开除的数据纠错员来说——这已经足够了。\n足够到让我忽略了一切不合理的地方。","exterior"),a("s0-2-1","前台小刘","receptionist","您好，请问是林墨先生吗？张总已经交代过了，请直接上电梯到7楼——第7号实验楼。","receptionist"),t("s0-2-2","第七号实验楼。我后来才知道，整个公司只有七个人在那里工作。其中六个——会在接下来的日子里——以不同的方式——死在我面前。","corridor"),o("s0-2-3","前台小刘保持着职业微笑，但她的眼神短暂地闪烁了一下。",[{text:'【礼貌回应】"谢谢，我自己上去就好。"',next:[t("s0-2-3a","你没有多问。乘电梯上楼。后来你发现——问正确的问题，在正确的时间——能救你的命。","corridor")]},{text:'【随口多问】"第7号楼是做什么研究的？"',next:[a("s0-2-3b","前台小刘","receptionist",'"蛋白质结构预测和酶催化研究。非常安全的基础研究。"\n她说到"安全"两个字时——语气微妙地顿了一下。',"receptionist"),t("s0-2-3c",'那时候我还不理解，为什么一个基础研究会需要单独的实验楼。以及为什么前台说"安全"时，像是在说服自己。',"corridor")],effects:{flag:"asked_receptionist"}}]),a("s0-3-1","清洁工老周","oldzhou","新来的？","oldzhou"),a("s0-3-2","林墨","linmo","是的，今天第一天报道。"),a("s0-3-3","老周","oldzhou","那边别去。B区，地下层。上个月有个研究员下去取样，回来以后整个人都不对了。现在还在休病假。\n另外——离心机三号有异响。录数据的时候别站太近。炸了三次了。","oldzhou"),t("s0-3-4","他说话的方式太平静了——像是在播报天气预报。而且——一个清洁工为什么知道离心机的编号？","corridor"),t("s0-4-0","开放办公区——6个工位围成一个不规则的环。阳光透过落地窗照进来，空气中飘着淡淡的咖啡香和某种培养基的味道。","office"),a("s0-4-1","小雅","xiaoya","啊！新——人——！","xiaoya"),a("s0-4-2","小雅","xiaoya","你是林墨对不对？张总邮件里有写！我叫小雅！生物信息学实习生！对了对了——你知道FASTA序列和BLAST算法的区别吗？","xiaoya"),s("s0-4-3","小雅突然凑近，眼睛亮晶晶的：",{question:"FASTA格式的第一行以什么符号开头？",options:[{label:"A",text:"@",correct:!1},{label:"B",text:">",correct:!0},{label:"C",text:"#",correct:!1},{label:"D",text:"$",correct:!1}],explanation:'FASTA格式是生物信息学中最常见的序列文件格式。第一行以">"开头，后接序列描述信息（如基因名称、物种来源）；后续行为核苷酸或氨基酸的单字母序列。BLAST算法正是基于FASTA格式进行序列比对搜索。',knowledgeId:"fasta_format",knowledgeTitle:"FASTA格式"},[a("s0-4-3c","小雅","xiaoya","哇！你懂生信！太好了——以后有人可以跟我讨论序列比对了！","xiaoya",{affection:{xiaoya:5}})],[a("s0-4-3w","小雅","xiaoya",'没关系~我可以教你！我最喜欢教人了。FASTA第一行以">"开头哦！记住啦~',"xiaoya",{affection:{xiaoya:2}})]),a("s0-4-4","林雪","linxue","小雅。别吓到新人。","linxue"),a("s0-4-5","林雪","linxue","你就是林墨？数据纠错背景？希望你的统计学比你的简历写得好。上周来的实习生连p值都算不对。","linxue"),o("s0-4-6","林雪的灰蓝色眼瞳冷冷地扫了你一眼。",[{text:'【谦虚回应】"我会努力的，请多指教。"',next:[a("s0-4-6a","林雪","linxue","……嗯。","linxue")]},{text:'【专业回击】"p<0.05的标准是Fisher定的，如果是多重比较需要考虑Bonferroni校正。"',next:[a("s0-4-6b","林雪","linxue","……记得到时候把校正后的q值也标注上。","linxue"),t("s0-4-6c","她的嘴角似乎上扬了0.1毫米。这是她入职以来第一次正眼看一个人。","office")],effects:{affection:{linxue:5},flag:"professional_response"}}]),a("s0-4-7","陈阳","chenyang","新同事！太好了！正好我需要人帮忙——你帮我确认一下，我该加多少微升的底物？","chenyang"),a("s0-4-8","陈阳","chenyang","我现在配的是辣根过氧化物酶的活性检测体系。总反应体积200微升，底物母液浓度10mM，需要最终浓度0.5mM——啊我数学不好——","chenyang"),s("s0-4-9","陈阳不好意思地挠了挠头，呆毛晃了晃。",{question:"总反应体系200μL，底物母液10mM，需要终浓度0.5mM。应加入多少体积的底物母液？",options:[{label:"A",text:"5μL",correct:!1},{label:"B",text:"10μL",correct:!0},{label:"C",text:"20μL",correct:!1},{label:"D",text:"50μL",correct:!1}],explanation:"使用稀释公式C₁V₁=C₂V₂：10mM × V₁ = 0.5mM × 200μL，V₁ = 10μL。辣根过氧化物酶(HRP)是一种常用的氧化还原酶，广泛用于ELISA和Western blot等生化检测。",knowledgeId:"c1v1c2v2",knowledgeTitle:"C₁V₁=C₂V₂稀释公式与辣根过氧化物酶(HRP)"},[a("s0-4-9c","陈阳","chenyang","谢谢！我差点加成50微升——那试管估计就炸了。","chenyang",{affection:{chenyang:5}})],[a("s0-4-9w","陈阳","chenyang","没关系没关系——反正也不是第一次炸了……还好这次没炸。","chenyang",{affection:{chenyang:2}})]),a("s0-4-10","王博士","wang","啊，新同事到了。","wang"),a("s0-4-11","王博士","wang","林墨……好名字。你父亲给你取的？","wang"),t("s0-4-12","他怎么知道我父亲？我简历上没写。","office"),a("s0-4-13","王博士","wang","既然来了——我顺便给你讲一下最近的项目。糖酵解——第一步，葡萄糖→6-磷酸葡萄糖，由己糖激酶催化。这一步不可逆。\n第三步——最关键——由磷酸果糖激酶-1(PFK-1)催化。这是整个糖酵解最重要的限速酶。","wang"),s("s0-4-14",'王博士在白板上"PFK-1"旁边画了一个大星号，然后转过来看着你。',{question:"为什么磷酸果糖激酶-1(PFK-1)是糖酵解最重要的限速酶？",options:[{label:"A",text:"因为它是唯一消耗ATP的酶",correct:!1},{label:"B",text:'因为它受到多种效应物的别构调节，是糖酵解的"总闸门"',correct:!0},{label:"C",text:"因为它的Km值最大",correct:!1},{label:"D",text:"因为它位于糖酵解的第一步",correct:!1}],explanation:"PFK-1受ATP抑制（高能荷时关闭糖酵解），受AMP/ADP和果糖-2,6-二磷酸激活（低能荷时开启糖酵解），是细胞能量代谢调控的核心节点。柠檬酸也抑制PFK-1——当TCA循环饱和时减缓糖酵解。",knowledgeId:"pfk1_regulation",knowledgeTitle:"PFK-1——糖酵解最重要的限速酶"},[a("s0-4-14c","王博士","wang","基础很扎实。比大多数实习生强。","wang",{affection:{wang:5}})],[a("s0-4-14w","王博士","wang","没关系。错误是最好的老师。记住——PFK-1被ATP抑制，被AMP激活。这是细胞在告诉身体：不缺能量就休息，缺能量就开工。","wang",{affection:{wang:3}})]),a("s0-4-15","苏菲亚","sophia","抱歉迟到了——和欧洲那边有个视频会议。","sophia"),a("s0-4-16","苏菲亚","sophia","新人？有趣。","sophia"),t("s0-4-17",'她说"有趣"时的语气——像是X射线晶体学家看到了一颗有趣的衍射斑点。',"office"),a("s0-4-18","张总","zhang","看来人到齐了。林墨——欢迎加入普罗米修斯。","zhang"),t("s0-4-19","他摘下一只手套，向你伸出手。手背上的皮肤——皱纹密布，有暗褐色的斑点。这不像是一个45岁男人的手。\n他很快又戴上了手套。","office"),a("s0-4-20","张总","zhang","我很期待你的表现。各位——今晚7点，B1核心实验室有个小型的入职欢迎会。林墨——一定要来。","zhang"),t("s0-4-21",'他说"一定要来"时——不像邀请。像命令。',"office"),a("s0-4-22","张总","zhang","入职培训的最后一项，我需要确认你的生化基础。不会太难——只是几个小问题。","zhang"),s("s0-4-23","张总靠在实验台边，皮质手套交叉放在身前。他的灰色眼瞳像是扫描仪。",{question:"蛋白质的二级结构主要包括哪几种？",options:[{label:"A",text:"α-螺旋、β-折叠、β-转角、无规卷曲",correct:!0},{label:"B",text:"一级结构、二级结构、三级结构、四级结构",correct:!1},{label:"C",text:"双螺旋、三叶草形、倒L形",correct:!1},{label:"D",text:"肽键、二硫键、氢键、离子键",correct:!1}],explanation:"蛋白质二级结构指多肽链主链的局部空间构象，主要由主链C=O与N-H之间的氢键维持。α-螺旋：3.6残基/圈，螺距0.54nm，氢键与螺旋轴平行。β-折叠：相邻β-股间的氢键形成片层结构。β-转角：4个残基的180°回折。无规卷曲：无固定二级结构的柔性区域。",knowledgeId:"protein_secondary_structure",knowledgeTitle:"蛋白质二级结构"},[a("s0-4-23c","张总","zhang","很好。","zhang"),t("s0-4-23cn","张总在笔记本上写了什么。后来你才知道——答对张总的问题，反而会让他更关注你。在这栋楼里——有时候装傻才是聪明的选择。","office")],[a("s0-4-23w","张总","zhang","没关系。入职后会有人教你。","zhang"),t("s0-4-23wn","他似乎松了口气。你的表现越差，他越不担心你发现问题。","office")]),s("s0-4-24",'张总继续："再来一个。DNA的Chargaff规则是什么？"',{question:"Chargaff规则指出，在双链DNA中——",options:[{label:"A",text:"DNA是右手双螺旋",correct:!1},{label:"B",text:"[A]=[T]，[G]=[C]",correct:!0},{label:"C",text:"DNA半保留复制",correct:!1},{label:"D",text:"一个基因对应一个酶",correct:!1}],explanation:"Chargaff规则(1950)：在双链DNA中，腺嘌呤(A)的含量等于胸腺嘧啶(T)，鸟嘌呤(G)等于胞嘧啶(C)。这是Watson和Crick提出DNA双螺旋模型(1953)的关键实验基础之一。",knowledgeId:"chargaff_rule",knowledgeTitle:"Chargaff规则与DNA双螺旋"},[a("s0-4-24c","张总","zhang","教科书一样的答案。","zhang")],[a("s0-4-24w","张总","zhang","没关系。","zhang")]),t("s0-6-0","傍晚。天台。天空是橙粉色的。城市在远处闪烁。","rooftop_day"),a("s0-6-1","陈阳","chenyang","我就猜你会来天台。新人的必经之地——一楼的咖啡太难喝了。","chenyang"),a("s0-6-2","陈阳","chenyang","其实我每天这个点都会上来。做了一天实验，需要看点不是实验室天花板的东西。\n你在前公司——是因为什么走的？","chenyang"),o("s0-6-3","陈阳看着你。夕阳在他温暖的棕色眼瞳里投下橙色的光。",[{text:'【坦诚相告】"被霸凌了。数据纠错纠到了领导的假数据。"',next:[a("s0-6-3a","陈阳","chenyang","……我理解。做对的事——在这个行业里——有时候是最贵的。","chenyang")],effects:{affection:{chenyang:3},flag:"honest_with_chenyang"}},{text:'【反问他】"那你呢？你为什么离开上一家？"',next:[a("s0-6-3b","陈阳","chenyang","因为……我做了一件我觉得对的事，然后发现——做对的事在这个行业里是最贵的。","chenyang"),t("s0-6-3bn","他没有继续说。但你注意到他握着咖啡罐的手指关节泛白了。","rooftop_day")],effects:{affection:{chenyang:3}}}]),a("s0-6-4","林雪","linxue","……我没打扰你们吧？","linxue"),a("s0-6-5","林雪","linxue","我只是上来看一下云。明天要跑X射线衍射——空气湿度太高的话，晶体分辨率会下降。","linxue"),t("s0-6-6","她的银色保温杯洒出几滴液体。她迅速擦掉了。但那几滴——闻起来不像是普通的咖啡。有一种淡淡的苦杏仁味。","rooftop_day"),a("s0-6-7","陈阳","chenyang","林雪姐的咖啡——她自己特调的配方。谁都不给尝。","chenyang"),a("s0-6-8","林雪","linxue","陈阳。你3号试剂柜的有机锂还没淬灭。如果明天着火——我不负责。","linxue"),t("s0-6-9","陈阳飞奔向楼梯。天台上只剩下林雪和你。\n她的肩膀线条似乎松弛了一点。","rooftop_day"),a("s0-6-10","林雪","linxue","你刚才在张总面前回答的问题……太标准了。像是教科书一样的答案。你在前公司到底是做什么的？","linxue"),o("s0-6-11","她的声音里有种奇怪的东西——既不是怀疑，也不是欣赏。更像是——一种警讯。",[{text:'【如实回答】"做数据纠错的。每天看几万行序列比对结果。"',next:[a("s0-6-11a","林雪","linxue","数据纠错。序列比对。\n……难怪。","linxue")]},{text:'【反问回去】"你的咖啡配方是什么？"',next:[a("s0-6-11b","林雪","linxue","……一个没有冒名顶替综合症的人不会问的问题。","linxue"),t("s0-6-11bn",'她的嘴角出现了你今天看到的第一丝真实的弧度——不是笑，更接近于一个正在考虑"这个人也许值得信任"的微表情。',"rooftop_day")],effects:{affection:{linxue:8}}}]),t("s0-7-0",'晚上7点。B1核心实验室。蓝色冷光。墙上贴着"欢迎新同事"的打印纸。',"b1_lab"),a("s0-7-1","张总","zhang","欢迎林墨加入普罗米修斯。希望在接下来的日子里，你能和团队——","zhang"),t("s0-7-2","他的声音顿了一下，捂住胸口。只是一瞬间——但你看到了他额头上渗出的冷汗。","b1_lab"),a("s0-7-3","张总","zhang","——愉快地工作。干杯。","zhang"),t("s0-7-4","突然——B1层的警报响了。","b1_lab"),t("s0-7-5","天花板上的红色警报灯开始旋转闪烁。发酵罐的嗡嗡声变成了尖锐的啸叫。","b1_lab"),a("s0-7-6","王博士","wang","这个警报频率——是B3的低温存储区！蛋白样本发生了异常聚集！","wang"),a("s0-7-7","林雪","linxue","发酵罐里的重组蛋白在——在变性！β-折叠含量在急剧下降，α-螺旋正在变为无规卷曲！\n不可能……这个pH和温度条件下蛋白不应该变性的！","linxue"),a("s0-7-8","陈阳","chenyang","大家快撤！通风系统检测到——","chenyang"),t("s0-7-9","他没能说完。","b1_lab"),c("s0-7-10","发酵罐的泄压阀爆开。白色的气雾在红色警报灯中弥漫开来。\n肺部的灼烧感。\n每一口呼吸都在加深疼痛。\n视野在缩小——边缘变黑——\n这就是……死亡吗？","b1_lab","/images/cg/cg_first_death.png"),t("s0-7-11","正在写入时间戳……\n组蛋白H3K27me3P标记完成……\n量子纠缠态锚定成功……\n意识回溯启动……\n回溯目标：上一个REM睡眠结束时刻","dark"),c("s0-7-12",'你猛地从床上坐起来！阳光从窗帘缝隙照进来。手机闹钟在响。\n\n日期：入职第一天，早上7:30。\n"我……我还活着？"\n我做了一个噩梦——还是——',"office","/images/cg/cg_reincarnation_awakening.png"),o("s0-7-13","你的手在发抖。阳光照在你的手背上——皮肤光滑。没有皱纹。\n手机屏幕显示：7月21日。入职第一天。",[{text:'【试图回忆】"发酵罐……蛋白变性……死亡……这不是梦"',next:[t("s0-7-13a","你闭上眼睛。那些画面像潮水一样涌回来——每一个细节都清晰得不像梦。发酵罐的温度读数。蛋白CD光谱的崩溃。陈阳没能说完的话。\n这不是梦。你活过了这一天——然后死了——然后回来了。","office")],effects:{flag:"remembered_death"}},{text:'【当作噩梦】"只是压力太大了吧。今天还要入职。"',next:[t("s0-7-13b","你选择不去想它。但你的手在不受控制地发抖。你知道今天会发生什么——但你告诉自己那不是真的。","office")]}]),i("prologue-end","▎序章完结\n▎解锁：轮回机制\n▎知识库条目：FASTA格式 | C₁V₁=C₂V₂ | PFK-1别构调控 | 蛋白质二级结构 | Chargaff规则\n▎第1章即将开始——蛋白质折叠异常事件\n\n你的选择——将决定这条路的走向。")])}}});